  call void @llvm.memcpy.p0.p0.i64(ptr %gep, ptr %ary, i64 16, i1 false)
  br label %loop

loop:                                             ; preds = %loop, %0
  %1 = phi i64 [ %i.next, %loop ], [ 0, %0 ]
  %i.next = add i64 %1, 1
  store i64 %i.next, ptr %a, align 4
  %gep.i = getelementptr i32, ptr %gep, i64 %1
  %val = load i32, ptr %gep.i, align 4
  call void @use.i32(i32 %val)
  %cmp = icmp eq i64 %i.next, 6
  br i1 %cmp, label %exit, label %loop

exit:                                             ; preds = %loop
  ret void
